package arrays.praticando.aprendendo;import java.util.Scanner;public class ExercicioArray{    public static void main(String[] args) {        String[] nomes = new String[3];        Scanner inputName = new Scanner(System.in);        for (int i = 0; i < nomes.length; i++) {            System.out.println("Qual seu nome? ");            String name = inputName.nextLine();            nomes[i] = name;        }        for (int c = 0; c < 3 ; c++) {            System.out.println(nomes[c]);        }    }}